import { zodResolver } from '@hookform/resolvers/zod';import { useForm } from 'react-hook-form';import { Button } from '@/components/ui/button';import { contractSchema } from '../schemas';import type { ContractFormValues,SupplierContract } from '../types';const cls='mt-1 h-10 w-full rounded-lg border border-slate-300 bg-white px-3 text-sm dark:border-slate-600 dark:bg-slate-800';
export const ContractForm=({contract,currency='PKR',onSubmit,onCancel,isLoading}:{contract?:SupplierContract|null;currency?:string;onSubmit:(v:ContractFormValues)=>void;onCancel:()=>void;isLoading?:boolean})=>{const today=new Date().toISOString().slice(0,10);const {register,handleSubmit,formState:{errors}}=useForm<ContractFormValues>({resolver:zodResolver(contractSchema),mode:'onTouched',defaultValues:contract?{contract_number:contract.contract_number,start_date:contract.start_date,end_date:contract.end_date,renewal_date:contract.renewal_date??'',contract_value:Number(contract.contract_value),currency:contract.currency,status:contract.status,attachment_name:contract.attachment_name??'',attachment_reference:contract.attachment_reference??'',notes:contract.notes??''}:{contract_number:'',start_date:today,end_date:today,renewal_date:'',contract_value:0,currency,status:'draft',attachment_name:'',attachment_reference:'',notes:''}});const input=(name:keyof ContractFormValues,label:string,type='text')=><label className="text-sm font-semibold">{label}<input type={type} step={type==='number'?'0.01':undefined} {...register(name)} className={cls}/>{errors[name]?<span className="block text-xs text-red-600">{String(errors[name]?.message)}</span>:null}</label>;return <form onSubmit={handleSubmit(onSubmit)} className="space-y-4"><div className="grid gap-4 sm:grid-cols-2">{input('contract_number','Contract Number')}{input('start_date','Start Date','date')}{input('end_date','End Date','date')}{input('renewal_date','Renewal Date','date')}{input('contract_value','Contract Value','number')}{input('currency','Currency')}<label className="text-sm font-semibold">Status<select {...register('status')} className={cls}>{['draft','active','expired','terminated','renewed'].map(x=><option key={x} value={x}>{x}</option>)}</select></label>{input('attachment_name','Attachment Name')}{input('attachment_reference','Attachment Reference','url')}</div><p className="text-xs text-slate-500">Attachment fields are placeholders; this module does not upload files.</p><label className="block text-sm font-semibold">Notes<textarea {...register('notes')} rows={3} className={`${cls} h-auto py-2`}/></label><div className="flex justify-end gap-2"><Button type="button" variant="secondary" onClick={onCancel}>Cancel</Button><Button type="submit" isLoading={isLoading}>Save Contract</Button></div></form>;};
